const chatId = "6585936467";
const now = new Date();
const dateNl = new Intl.DateTimeFormat("nl-NL", {
  weekday: "long", day: "numeric", month: "long", year: "numeric",
  hour: "2-digit", minute: "2-digit", timeZone: "Europe/Amsterdam"
}).format(now);

const feeds = [
  { section: "world", url: "https://news.google.com/rss/topstories?hl=en&gl=US&ceid=US:en" },
  { section: "world", url: "https://news.google.com/rss/headlines/section/topic/WORLD?hl=en&gl=US&ceid=US:en" },
  { section: "world", url: "https://feeds.bbci.co.uk/news/world/rss.xml" },
  { section: "hk", url: "https://news.google.com/rss/search?q=Hong%20Kong%20OR%20HK%20when%3A24h&hl=en-HK&gl=HK&ceid=HK:en" },
  { section: "hk", url: "https://news.google.com/rss/search?q=Hong%20Kong%20economy%20politics%20markets%20when%3A24h&hl=en-HK&gl=HK&ceid=HK:en" }
];

function escapeHtml(value = "") {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function decodeXml(value = "") {
  return value
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, "$1")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, "\"")
    .replace(/&#39;|&apos;/g, "'")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tag(block, name) {
  const re = new RegExp("<" + name + "[^>]*>([\\s\\S]*?)<\\/" + name + ">", "i");
  const m = block.match(re);
  return decodeXml((m && m[1]) || "");
}

function sourceFromTitle(title) {
  const parts = title.split(" - ");
  return parts.length > 1 ? parts.pop().trim() : "bron";
}

function cleanTitle(title) {
  return title.replace(/\s+-\s+[^-]{2,80}$/, "").trim();
}

function category(text) {
  const t = text.toLowerCase();
  if (/hong kong|beijing|china|greater bay|national security|legco|chief executive/.test(t)) return "China/HK";
  if (/stock|market|shares|rates|inflation|oil|trade|tariff|bank|yen|dollar|economy|gdp|property/.test(t)) return "Markten";
  if (/war|strike|missile|iran|israel|ukraine|russia|taiwan|military|ceasefire|sanction/.test(t)) return "Geopolitiek";
  if (/ai|chip|semiconductor|tech|cyber|data|social media|platform/.test(t)) return "Tech";
  if (/flu|health|hospital|vaccine|covid|storm|typhoon|climate/.test(t)) return "Risico";
  return "Topnieuws";
}

function shortText(value, max = 92) {
  const cleaned = String(value || "")
    .replace(/\s+-\s+[^-]{2,80}$/, "")
    .replace(/\s+/g, " ")
    .trim();
  if (cleaned.length <= max) return cleaned;
  return cleaned.slice(0, max - 3).replace(/\s+\S*$/, "") + "...";
}

function oneLiner(item) {
  return category(item.title + " " + item.description) + ": " + shortText(item.title || item.description, 88);
}

function score(item) {
  const t = (item.title + " " + item.description).toLowerCase();
  let s = item.section === "hk" ? 15 : 0;
  const terms = ["breaking", "hong kong", "china", "beijing", "trump", "iran", "israel", "ukraine", "russia", "taiwan", "oil", "market", "rate", "central bank", "stocks", "tariff", "election", "ai", "chip", "court", "security", "typhoon"];
  for (const term of terms) if (t.includes(term)) s += 4;
  const age = item.pubDate ? Math.max(0, (Date.now() - item.pubDate.getTime()) / 36e5) : 24;
  s += Math.max(0, 18 - age);
  return s;
}

async function readFeed(feed) {
  const xml = await this.helpers.httpRequest({
    method: "GET",
    url: feed.url,
    headers: {
      "User-Agent": "Mozilla/5.0 Aida n8n news brief/1.0",
      "Accept": "application/rss+xml, application/xml, text/xml, */*"
    },
    timeout: 20000,
    json: false,
  });
  return [...String(xml).matchAll(/<item[\s\S]*?<\/item>/gi)].map((m) => {
    const block = m[0];
    const rawTitle = tag(block, "title");
    const pub = tag(block, "pubDate");
    const item = {
      section: feed.section,
      title: cleanTitle(rawTitle),
      source: tag(block, "source") || sourceFromTitle(rawTitle),
      link: tag(block, "link"),
      description: tag(block, "description"),
      pubDate: pub ? new Date(pub) : null,
    };
    item.score = score(item);
    return item;
  }).filter((x) => x.title && x.link);
}

const settled = await Promise.allSettled(feeds.map((feed) => readFeed.call(this, feed)));
const all = settled.flatMap((r) => r.status === "fulfilled" ? r.value : []);
const errors = settled
  .map((r, i) => r.status === "rejected" ? feeds[i].url + ": " + (r.reason && r.reason.message ? r.reason.message : String(r.reason)) : null)
  .filter(Boolean);

const seen = new Set();
const unique = [];
for (const item of all.sort((a, b) => b.score - a.score)) {
  const key = item.title.toLowerCase().replace(/[^a-z0-9]+/g, " ").slice(0, 90);
  if (seen.has(key)) continue;
  seen.add(key);
  unique.push(item);
}

const world = unique.filter((x) => x.section === "world").slice(0, 5);
const hk = unique.filter((x) => x.section === "hk").slice(0, 5);

function itemLine(item, index) {
  const line = escapeHtml(oneLiner(item));
  const url = escapeHtml(item.link);
  return String(index + 1) + ". " + line + " · <a href=\"" + url + "\">bron</a>";
}

let message = "<b>Goedemorgen</b>\n" + escapeHtml(dateNl) + " in Amsterdam\n\n";
message += "<b>Wereldnieuws</b>\n" + (world.length ? world.map(itemLine).join("\n") : "Geen bruikbare wereldnieuwsitems gevonden.") + "\n\n";
message += "<b>HK nieuws</b>\n" + (hk.length ? hk.map(itemLine).join("\n") : "Geen bruikbare HK-nieuwsitems gevonden.") + "\n\n";
if (errors.length && world.length + hk.length < 5) message += "Bronwaarschuwing: " + escapeHtml(errors.slice(0, 2).join(" | ")) + "\n";
message += "<i>Aandachtspunt: markten, China/HK, energie en geopolitiek risico.</i>";

return [{ json: { chatId, message, worldCount: world.length, hkCount: hk.length, messageLength: message.length, feedErrors: errors } }];

const chatId = "6585936467";
const now = new Date();
const dateNl = new Intl.DateTimeFormat("nl-NL", {
  weekday: "long", day: "numeric", month: "long", year: "numeric",
  hour: "2-digit", minute: "2-digit", timeZone: "Europe/Amsterdam"
}).format(now);

function escapeHtml(value = "") {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function clean(value = "") {
  return String(value)
    .replace(/&nbsp;/g, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function short(value, max = 180) {
  const text = clean(value);
  if (text.length <= max) return text;
  return text.slice(0, max - 3).replace(/\s+\S*$/, "") + "...";
}

function dayLabel(iso) {
  return new Intl.DateTimeFormat("nl-NL", {
    weekday: "short", day: "numeric", month: "short", timeZone: "Europe/Amsterdam"
  }).format(new Date(iso));
}

const data = await this.helpers.httpRequest({
  method: "GET",
  url: "https://data.buienradar.nl/2.0/feed/json",
  headers: {
    "User-Agent": "Mozilla/5.0 Aida n8n buienradar brief/1.0",
    "Accept": "application/json"
  },
  timeout: 20000,
  json: true,
});

const forecast = data.forecast || {};
const report = forecast.weatherreport || {};
const shortterm = forecast.shortterm || {};
const longterm = forecast.longterm || {};
const days = Array.isArray(forecast.fivedayforecast) ? forecast.fivedayforecast.slice(0, 5) : [];

let message = "<b>Buienradar weekverwachting</b>\n" + escapeHtml(dateNl) + " in Amsterdam\n\n";
if (report.title) message += "<b>" + escapeHtml(clean(report.title)) + "</b>\n";
if (report.summary) message += escapeHtml(short(report.summary, 240)) + "\n\n";

if (shortterm.forecast) {
  message += "<b>Korte termijn</b>\n" + escapeHtml(short(shortterm.forecast, 240)) + "\n\n";
}
if (longterm.forecast) {
  message += "<b>Later in de week</b>\n" + escapeHtml(short(longterm.forecast, 240)) + "\n\n";
}

if (days.length) {
  message += "<b>Dagoverzicht</b>\n";
  message += days.map((d) => {
    const temp = d.mintemperature + "-" + d.maxtemperature + "°C";
    const rain = "regen " + (d.rainChance ?? "?") + "%";
    const mm = d.mmRainMin != null && d.mmRainMax != null ? ", " + d.mmRainMin + "-" + d.mmRainMax + " mm" : "";
    const sun = d.sunChance != null ? ", zon " + d.sunChance + "%" : "";
    const wind = d.windDirection ? ", wind " + String(d.windDirection).toUpperCase() + " " + d.wind : "";
    return "• " + escapeHtml(dayLabel(d.day)) + ": " + escapeHtml(temp + ", " + rain + mm + sun + wind + " - " + clean(d.weatherdescription));
  }).join("\n") + "\n\n";
}

message += "Bron: <a href=\"https://www.buienradar.nl\">Buienradar.nl</a>";
return [{ json: { chatId, message, days: days.length } }];

const items = $input.all().map((item) => item.json);

function text(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function fmt(value, allDay) {
  if (!value) return '';
  if (allDay || /^\d{4}-\d{2}-\d{2}$/.test(value)) {
    return new Intl.DateTimeFormat('nl-NL', {
      timeZone: 'Europe/Amsterdam',
      weekday: 'short',
      day: '2-digit',
      month: '2-digit',
    }).format(new Date(value + 'T00:00:00+02:00'));
  }
  return new Intl.DateTimeFormat('nl-NL', {
    timeZone: 'Europe/Amsterdam',
    weekday: 'short',
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  }).format(new Date(value));
}

const events = items
  .filter((event) => event && event.status !== 'cancelled')
  .map((event) => {
    const start = event.start?.dateTime || event.start?.date || event.start || '';
    const end = event.end?.dateTime || event.end?.date || event.end || '';
    return {
      id: event.id,
      title: text(event.summary || '(geen titel)'),
      start,
      end,
      allDay: !!event.start?.date,
      location: text(event.location || ''),
    };
  })
  .sort((a, b) => String(a.start).localeCompare(String(b.start)));

let answer;
if (!events.length) {
  answer = 'Ik vind geen afspraken in die periode.';
} else {
  answer = events.slice(0, 20).map((event) => {
    const line = '- ' + fmt(event.start, event.allDay) + ': ' + event.title;
    return event.location ? line + ' (' + event.location + ')' : line;
  }).join('\n');
}

return [{
  json: {
    ok: true,
    calendar: 'Ryan Private',
    eventCount: events.length,
    events,
    answer,
  },
}];

const contacts = $input.all().map((item) => item.json).map((person) => {
  const name = person.names?.[0]?.displayName || person.names?.[0]?.unstructuredName || '';
  const email = person.emailAddresses?.[0]?.value || '';
  return { name, email };
}).filter((contact) => contact.name || contact.email);
return [{ json: { ok: true, contacts, count: contacts.length, first: contacts[0] || null } }];
